import React, { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import api from '../data/api';

const diffColors = { easy: '#22c55e', medium: '#f59e0b', hard: '#ef4444' };

export default function AssignmentPage() {
  const { courseId, level, assignmentId } = useParams();
  const navigate = useNavigate();
  const [assignment, setAssignment] = useState(null);
  const [code, setCode] = useState('');
  const [output, setOutput] = useState(null);
  const [running, setRunning] = useState(false);
  const [showHints, setShowHints] = useState(false);
  const [showSolution, setShowSolution] = useState(false);
  const [submitted, setSubmitted] = useState(false);

  useEffect(() => {
    api.get(`/courses/${courseId}`).then(r => {
      const lvl = r.data.levels.find(l => l.name === level);
      const a = lvl?.assignments?.find(a => a._id === assignmentId);
      if (a) { setAssignment(a); setCode(a.starterCode || '// Write your solution here\n'); }
    });
  }, [courseId, level, assignmentId]);

  const submit = async () => {
    setRunning(true);
    setOutput(null);
    await new Promise(r => setTimeout(r, 900));
    try {
      await api.post('/progress/topic', { courseId, topicId: assignmentId, level, totalTopics: 10 });
    } catch {}
    setOutput({ status: 'submitted' });
    setSubmitted(true);
    setRunning(false);
  };

  if (!assignment) return <div style={{ background: '#0f172a', minHeight: '100vh', color: '#6b7280', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>Loading...</div>;

  return (
    <div style={{ display: 'flex', height: 'calc(100vh - 60px)', background: '#0f172a', overflow: 'hidden' }}>
      {/* Left */}
      <div style={{ width: '42%', display: 'flex', flexDirection: 'column', borderRight: '1px solid #1f2937', overflowY: 'auto' }}>
        <div style={{ background: '#111827', borderBottom: '1px solid #1f2937', padding: '0.75rem 1rem', display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
          <button onClick={() => navigate(`/course/${courseId}`)} style={{ background: 'none', border: 'none', color: '#6b7280', cursor: 'pointer', fontSize: '0.82rem' }}>←</button>
          <span style={{ color: '#9ca3af', fontSize: '0.85rem', fontWeight: 600 }}>📝 Assignment</span>
        </div>
        <div style={{ padding: '1.5rem' }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem', marginBottom: '1rem' }}>
            <h2 style={{ color: '#f1f5f9', fontWeight: 700, fontSize: '1.1rem', margin: 0 }}>{assignment.title}</h2>
            <span style={{ color: diffColors[assignment.difficulty], background: diffColors[assignment.difficulty] + '22', padding: '0.2rem 0.6rem', borderRadius: '20px', fontSize: '0.75rem', fontWeight: 700 }}>{assignment.difficulty}</span>
          </div>
          <p style={{ color: '#9ca3af', lineHeight: 1.7, fontSize: '0.92rem', marginBottom: '1.5rem' }}>{assignment.description}</p>

          {assignment.instructions && (
            <div style={{ background: '#1f2937', borderRadius: '10px', padding: '1rem', marginBottom: '1.25rem' }}>
              <div style={{ color: '#7c6af7', fontWeight: 600, fontSize: '0.82rem', marginBottom: '0.5rem', textTransform: 'uppercase' }}>📋 Instructions</div>
              <p style={{ color: '#9ca3af', fontSize: '0.88rem', lineHeight: 1.6, margin: 0 }}>{assignment.instructions}</p>
            </div>
          )}

          {assignment.hints?.length > 0 && (
            <div style={{ marginBottom: '1.25rem' }}>
              <button onClick={() => setShowHints(!showHints)}
                style={{ background: '#1f2937', border: '1px solid #374151', borderRadius: '8px', padding: '0.6rem 1rem', color: '#f59e0b', cursor: 'pointer', fontSize: '0.85rem', fontWeight: 600, width: '100%', textAlign: 'left' }}>
                💡 {showHints ? 'Hide' : 'Show'} Hints ({assignment.hints.length})
              </button>
              {showHints && (
                <div style={{ background: '#1f2937', borderRadius: '0 0 8px 8px', padding: '1rem', borderTop: 'none', border: '1px solid #374151', borderTop: 'none' }}>
                  {assignment.hints.map((h, i) => (
                    <div key={i} style={{ color: '#9ca3af', fontSize: '0.85rem', marginBottom: '0.4rem' }}>• {h}</div>
                  ))}
                </div>
              )}
            </div>
          )}

          {assignment.solution && (
            <div>
              <button onClick={() => setShowSolution(!showSolution)}
                style={{ background: '#1f2937', border: '1px solid #374151', borderRadius: '8px', padding: '0.6rem 1rem', color: '#ef4444', cursor: 'pointer', fontSize: '0.85rem', fontWeight: 600, width: '100%', textAlign: 'left' }}>
                🔑 {showSolution ? 'Hide' : 'View'} Solution
              </button>
              {showSolution && (
                <pre style={{ background: '#0f172a', border: '1px solid #374151', borderRadius: '0 0 8px 8px', padding: '1rem', color: '#a5f3fc', fontFamily: 'monospace', fontSize: '0.83rem', overflowX: 'auto', marginTop: 0, whiteSpace: 'pre-wrap' }}>
                  {assignment.solution}
                </pre>
              )}
            </div>
          )}
        </div>
      </div>

      {/* Right */}
      <div style={{ flex: 1, display: 'flex', flexDirection: 'column' }}>
        <div style={{ background: '#111827', borderBottom: '1px solid #1f2937', padding: '0.6rem 1rem', display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
          <span style={{ color: '#6b7280', fontSize: '0.82rem', fontWeight: 600 }}>{assignment.language}</span>
          <div style={{ display: 'flex', gap: '0.5rem' }}>
            <button onClick={() => setCode(assignment.starterCode || '')}
              style={{ padding: '0.35rem 0.8rem', background: 'transparent', border: '1px solid #374151', borderRadius: '6px', color: '#6b7280', cursor: 'pointer', fontSize: '0.8rem' }}>
              Reset
            </button>
            <button onClick={submit} disabled={running || submitted}
              style={{ padding: '0.35rem 1.2rem', background: submitted ? '#22c55e' : running ? '#374151' : '#7c6af7', border: 'none', borderRadius: '6px', color: '#fff', cursor: running || submitted ? 'not-allowed' : 'pointer', fontSize: '0.82rem', fontWeight: 700 }}>
              {submitted ? '✓ Submitted' : running ? '⏳ Submitting...' : 'Submit Assignment'}
            </button>
          </div>
        </div>

        <textarea
          value={code}
          onChange={e => setCode(e.target.value)}
          spellCheck={false}
          style={{ flex: 1, background: '#1e1e2e', color: '#cdd6f4', border: 'none', padding: '1rem', fontFamily: '"Fira Code", monospace', fontSize: '0.88rem', resize: 'none', outline: 'none', lineHeight: 1.6 }}
        />

        <div style={{ height: '120px', background: '#111827', borderTop: '1px solid #1f2937', overflow: 'auto' }}>
          <div style={{ padding: '0.6rem 1rem', borderBottom: '1px solid #1f2937', color: '#6b7280', fontSize: '0.8rem', fontWeight: 600 }}>OUTPUT</div>
          <div style={{ padding: '1rem' }}>
            {running && <div style={{ color: '#f59e0b', fontSize: '0.85rem' }}>⏳ Submitting...</div>}
            {!running && !output && <div style={{ color: '#374151', fontSize: '0.85rem' }}>Submit your assignment to record progress</div>}
            {output?.status === 'submitted' && (
              <div style={{ color: '#22c55e', fontWeight: 700, fontSize: '0.9rem' }}>✓ Assignment submitted successfully! +10 XP earned</div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}
